package caching

import (
	"container/list"
	"encoding/json"
	"net/http"
	"sync"
	"time"
)

// LRUCache is a thread-safe Least Recently Used cache.
// When capacity is reached, the least-recently-used entry is evicted.
type LRUCache struct {
	capacity  int
	mu        sync.Mutex
	evictList *list.List
	items     map[string]*list.Element
}

type entry struct {
	key   string
	value any
	expAt time.Time
}

func NewLRUCache(capacity int) *LRUCache {
	return &LRUCache{
		capacity:  capacity,
		evictList: list.New(),
		items:     make(map[string]*list.Element),
	}
}

// Get retrieves a value. Returns (value, true) on cache HIT.
// On cache MISS, the entry is evicted and (nil, false) is returned.
func (c *LRUCache) Get(key string) (any, bool) {
	c.mu.Lock()
	defer c.mu.Unlock()

	el, ok := c.items[key]
	if !ok {
		return nil, false // cache MISS — key not present
	}

	ent := el.Value.(*entry)
	if time.Now().After(ent.expAt) {
		c.removeElement(el)
		return nil, false // cache MISS — TTL expired
	}

	c.evictList.MoveToFront(el) // mark as recently used
	return ent.value, true      // cache HIT
}

// Set inserts or updates a key with the given TTL.
// If the cache is full, the least-recently-used entry is evicted first.
func (c *LRUCache) Set(key string, value any, ttl time.Duration) {
	c.mu.Lock()
	defer c.mu.Unlock()

	if el, ok := c.items[key]; ok {
		c.evictList.MoveToFront(el)
		ent := el.Value.(*entry)
		ent.value = value
		ent.expAt = time.Now().Add(ttl)
		return
	}

	if c.evictList.Len() >= c.capacity {
		c.evictOldest()
	}

	ent := &entry{key: key, value: value, expAt: time.Now().Add(ttl)}
	el := c.evictList.PushFront(ent)
	c.items[key] = el
}

func (c *LRUCache) evictOldest() {
	el := c.evictList.Back()
	if el != nil {
		c.removeElement(el)
	}
}

func (c *LRUCache) removeElement(el *list.Element) {
	c.evictList.Remove(el)
	delete(c.items, el.Value.(*entry).key)
}

var cache = NewLRUCache(1000)

// findUser simulates a database fetch — replace with your repository in production.
var findUser = func(userID string) (any, error) {
	return map[string]string{"id": userID, "name": "Example User"}, nil
}

// GetUser demonstrates a cache-aside (lazy-loading) pattern.
// 1. Check the cache — return immediately on HIT (fast path).
// 2. On MISS — fetch from the database and populate the cache.
func GetUser(w http.ResponseWriter, r *http.Request) {
	userID := r.PathValue("id")
	cacheKey := "user:" + userID

	if data, ok := cache.Get(cacheKey); ok {
		w.Header().Set("X-Cache", "HIT")
		_ = json.NewEncoder(w).Encode(data)
		return
	}

	user, err := findUser(userID)
	if err != nil {
		http.Error(w, "user not found", http.StatusNotFound)
		return
	}

	cache.Set(cacheKey, user, 5*time.Minute)

	w.Header().Set("X-Cache", "MISS")
	_ = json.NewEncoder(w).Encode(user)
}

package caching

import (
	"encoding/json"
	"net/http"
)

// Anti-pattern: shared mutable map without synchronization, no eviction, and no TTL.
// Concurrent requests can race; memory grows without bound.
var leakyUserCache = make(map[string]any)

// GetUserLeaky shows what not to do when layering HTTP handlers over a cache.
func GetUserLeaky(w http.ResponseWriter, r *http.Request) {
	userID := r.PathValue("id")

	if u, ok := leakyUserCache[userID]; ok {
		w.Header().Set("X-Cache", "HIT")
		_ = json.NewEncoder(w).Encode(u)
		return
	}

	u := map[string]string{"id": userID, "name": "Example User"}
	leakyUserCache[userID] = u
	_ = json.NewEncoder(w).Encode(u)
}

